DROP TABLE IF EXISTS `tarefas_tarefas`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tarefas_tarefas` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `recorrente` tinyint(1) NOT NULL,
  `frequencia_recorrencia` varchar(20) NOT NULL,
  `data_fim_recorrencia` date DEFAULT NULL,
  `titulo` varchar(200) NOT NULL,
  `descricao` longtext NOT NULL,
  `data_criacao` datetime(6) NOT NULL,
  `data_atualizacao` datetime(6) NOT NULL,
  `data_inicio` datetime(6) DEFAULT NULL,
  `prazo` datetime(6) DEFAULT NULL,
  `concluida_em` datetime(6) DEFAULT NULL,
  `status` varchar(20) NOT NULL,
  `prioridade` varchar(10) NOT NULL,
  `projeto` varchar(100) NOT NULL,
  `duracao_prevista` bigint DEFAULT NULL,
  `tempo_gasto` bigint DEFAULT NULL,
  `dias_lembrete` int unsigned NOT NULL,
  `ata_reuniao` longtext NOT NULL,
  `filial_id` bigint NOT NULL,
  `responsavel_id` bigint DEFAULT NULL,
  `tarefa_recorrencia_pai_id` bigint DEFAULT NULL,
  `usuario_id` bigint DEFAULT NULL,
  `aviso_fim_enviado_em` datetime(6) DEFAULT NULL,
  `dias_aviso_fim_recorrencia` int unsigned NOT NULL,
  `lembrete_enviado_em` datetime(6) DEFAULT NULL,
  `recorrencia_encerrada` tinyint(1) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `tarefas_tarefas_responsavel_id_f9558aa5` (`responsavel_id`),
  KEY `tarefas_tarefas_usuario_id_7497bb31_fk_usuario_usuario_id` (`usuario_id`),
  KEY `tarefas_tar_status_00de63_idx` (`status`,`prazo`),
  KEY `tarefas_tar_filial__cd60ea_idx` (`filial_id`,`status`),
