INSERT INTO `treinamentos_aulaead` VALUES (2,'O que Ã© a CIPA?','Conceito, objetivo e importÃ¢ncia da CIPA nas organizaÃ§Ãµes.',1,'video_externo','','','https://www.youtube.com/watch?v=dQw4w9WgXcQ','',15,1,1,'2026-03-07 22:22:24.621893',2),(3,'HistÃ³rico da NR-5','EvoluÃ§Ã£o da norma desde sua criaÃ§Ã£o atÃ© as atualizaÃ§Ãµes mais recentes.',2,'texto','<h3>HistÃ³rico da NR-5</h3>\n<p>A NR-5 foi aprovada pela Portaria nÂº 3.214, de 08 de junho de 1978, pelo MinistÃ©rio do Trabalho.</p>\n<h4>Principais marcos:</h4>\n<ul>\n    <li><strong>1978</strong> â€” PublicaÃ§Ã£o original da NR-5</li>\n    <li><strong>1999</strong> â€” Reforma ampla com Portaria 08/1999</li>\n    <li><strong>2011</strong> â€” AtualizaÃ§Ã£o da Portaria 14/2011</li>\n    <li><strong>2022</strong> â€” Nova redaÃ§Ã£o incluindo prevenÃ§Ã£o ao assÃ©dio</li>\n</ul>\n<p>A norma atual prevÃª a criaÃ§Ã£o da CIPA em todos os estabelecimentos que se enquadrem\nno dimensionamento do Quadro I da NR-5.</p>','','','',10,1,1,'2026-03-07 22:22:24.639777',2),(4,'Dimensionamento da CIPA','Como calcular o nÃºmero de membros conforme o CNAE e quantidade de empregados.',3,'texto','<h3>Dimensionamento da CIPA</h3>\n<p>O dimensionamento Ã© feito pelo <strong>Quadro I da NR-5</strong>, cruzando:</p>\n<ol>\n    <li>O grupo econÃ´mico (CNAE) do estabelecimento</li>\n    <li>O nÃºmero de empregados</li>\n</ol>\n<table class=\'table table-bordered\'>\n    <thead><tr><th>NÂº Empregados</th><th>Efetivos</th><th>Suplentes</th></tr></thead>\n    <tbody>\n        <tr><td>20 a 29</td><td>1</td><td>1</td></tr>\n        <tr><td>30 a 50</td><td>2</td><td>2</td></tr>\n        <tr><td>51 a 80</td><td>3</td><td>3</td></tr>\n        <tr><td>81 a 120</td><td>4</td><td>3</td></tr>\n        <tr><td>121 a 140</td><td>5</td><td>4</td></tr>\n    </tbody>\n</table>','','','',12,1,1,'2026-03-07 22:22:24.658472',2),(5,'AtribuiÃ§Ãµes dos Membros da CIPA','Responsabilidades do presidente, vice-presidente, secretÃ¡rio e demais membros.',1,'video_externo','','','https://www.youtube.com/watch?v=dQw4w9WgXcQ','',20,1,1,'2026-03-07 22:22:24.694029',3),(6,'ReuniÃµes OrdinÃ¡rias e ExtraordinÃ¡rias','Como conduzir reuniÃµes, atas e deliberaÃ§Ãµes da CIPA.',2,'texto','<h3>ReuniÃµes da CIPA</h3>\n<h4>ReuniÃµes OrdinÃ¡rias</h4>\n<p>Devem ser realizadas <strong>mensalmente</strong>, durante o expediente, em local apropriado. Ã‰ obrigatÃ³ria a lavratura de ata.</p>\n<h4>ReuniÃµes ExtraordinÃ¡rias</h4>\n<p>Convocadas quando houver:</p>\n<ul>\n    <li>DenÃºncia de situaÃ§Ã£o de risco grave e iminente</li>\n    <li>OcorrÃªncia de acidente de trabalho grave ou fatal</li>\n    <li>SolicitaÃ§Ã£o expressa de uma das representaÃ§Ãµes</li>\n</ul>','','','',15,1,1,'2026-03-07 22:22:24.711007',3),(7,'Mapa de Riscos','ElaboraÃ§Ã£o do mapa de riscos ambientais do estabelecimento.',3,'video_externo','','','https://www.youtube.com/watch?v=dQw4w9WgXcQ','',25,1,1,'2026-03-07 22:22:24.729027',3),(8,'Processo Eleitoral da CIPA','Passo a passo da eleiÃ§Ã£o: edital, inscriÃ§Ã£o, votaÃ§Ã£o e posse.',1,'texto','<h3>Processo Eleitoral</h3>\n<h4>Etapas obrigatÃ³rias:</h4>\n<ol>\n    <li><strong>60 dias antes do tÃ©rmino do mandato:</strong> Convocar eleiÃ§Ã£o</li>\n    <li><strong>45 dias antes:</strong> Publicar e divulgar edital</li>\n    <li><strong>15 dias antes:</strong> Encerrar inscriÃ§Ãµes</li>\n    <li><strong>Dia da eleiÃ§Ã£o:</strong> VotaÃ§Ã£o secreta durante o expediente</li>\n    <li><strong>ApÃ³s apuraÃ§Ã£o:</strong> Posse dos eleitos no primeiro dia do mandato</li>\n</ol>\n<div class=\'alert alert-warning\'>\n    <strong>âš ï¸ Importante:</strong> O voto Ã© secreto e a eleiÃ§Ã£o deve ser realizada em dia normal de trabalho.\n</div>','','','',18,1,1,'2026-03-07 22:22:24.766271',4),(9,'SIPAT â€” Semana Interna de PrevenÃ§Ã£o','Planejamento e execuÃ§Ã£o da Semana Interna de PrevenÃ§Ã£o de Acidentes.',2,'video_externo','','','https://www.youtube.com/watch?v=dQw4w9WgXcQ','',20,1,1,'2026-03-07 22:22:24.785003',4),(10,'O que Ã© EPI?','DefiniÃ§Ã£o, finalidade e quando o EPI deve ser utilizado.',1,'video_externo','','','https://www.youtube.com/watch?v=dQw4w9WgXcQ','',12,1,1,'2026-03-07 22:22:25.829846',5),(11,'Certificado de AprovaÃ§Ã£o (CA)','O que Ã© o CA, sua importÃ¢ncia e como verificar a validade.',2,'texto','<h3>Certificado de AprovaÃ§Ã£o (CA)</h3>\n<p>Todo EPI comercializado no Brasil precisa ter o <strong>Certificado de AprovaÃ§Ã£o (CA)</strong>,\nemitido pelo MinistÃ©rio do Trabalho.</p>\n<h4>InformaÃ§Ãµes do CA:</h4>\n<ul>\n    <li>NÃºmero do CA</li>\n    <li>Nome do fabricante/importador</li>\n    <li>Data de validade (mÃ¡ximo 5 anos)</li>\n    <li>Norma tÃ©cnica de referÃªncia</li>\n</ul>\n<div class=\'alert alert-danger\'>\n    <strong>â›” AtenÃ§Ã£o:</strong> Ã‰ proibido o uso de EPI sem CA vÃ¡lido!\n</div>','','','',10,1,1,'2026-03-07 22:22:25.847831',5),(12,'EPIs para ProteÃ§Ã£o da CabeÃ§a','Capacetes, bonÃ©s e capuzes de proteÃ§Ã£o.',1,'video_externo','','','https://www.youtube.com/watch?v=dQw4w9WgXcQ','',15,1,1,'2026-03-07 22:22:25.884093',6),(13,'EPIs para ProteÃ§Ã£o RespiratÃ³ria','Respiradores, mÃ¡scaras e filtros â€” seleÃ§Ã£o por tipo de contaminante.',2,'video_externo','','','https://www.youtube.com/watch?v=dQw4w9WgXcQ','',18,1,1,'2026-03-07 22:22:25.902850',6),(14,'EPIs para ProteÃ§Ã£o das MÃ£os e Membros Superiores','Luvas de diferentes materiais e suas aplicaÃ§Ãµes.',3,'texto','<h3>ProteÃ§Ã£o das MÃ£os</h3>\n<table class=\'table table-striped\'>\n    <thead><tr><th>Tipo de Luva</th><th>ProteÃ§Ã£o Contra</th></tr></thead>\n    <tbody>\n        <tr><td>Luva de LÃ¡tex</td><td>Agentes biolÃ³gicos, produtos quÃ­micos leves</td></tr>\n        <tr><td>Luva de Nitrila</td><td>Solventes, Ã³leos, produtos quÃ­micos</td></tr>\n        <tr><td>Luva de Vaqueta</td><td>AbrasÃ£o, cortes leves, calor moderado</td></tr>\n        <tr><td>Luva de Malha de AÃ§o</td><td>Cortes severos (aÃ§ougues, indÃºstria)</td></tr>\n        <tr><td>Luva Isolante</td><td>Choque elÃ©trico (classe conforme tensÃ£o)</td></tr>\n    </tbody>\n</table>','','','',12,1,1,'2026-03-07 22:22:25.920415',6),(15,'O que Ã© Ergonomia?','DefiniÃ§Ã£o e campos de atuaÃ§Ã£o da ergonomia.',1,'video_externo','','','https://www.youtube.com/watch?v=dQw4w9WgXcQ','',15,1,1,'2026-03-07 22:22:26.504717',7),(16,'AnÃ¡lise ErgonÃ´mica do Trabalho (AET)','Metodologia para avaliaÃ§Ã£o ergonÃ´mica do posto de trabalho.',2,'texto','<h3>AnÃ¡lise ErgonÃ´mica do Trabalho</h3>\n<p>A AET Ã© obrigatÃ³ria conforme a NR-17 e deve contemplar:</p>\n<ol>\n    <li>AnÃ¡lise da demanda</li>\n    <li>AnÃ¡lise da tarefa</li>\n    <li>AnÃ¡lise da atividade</li>\n    <li>DiagnÃ³stico</li>\n    <li>RecomendaÃ§Ãµes</li>\n</ol>','','','',20,1,1,'2026-03-07 22:22:26.522658',7),(17,'Postura Correta no Computador','Ajuste de cadeira, monitor, teclado e mouse.',1,'video_externo','','','https://www.youtube.com/watch?v=dQw4w9WgXcQ','',18,1,1,'2026-03-07 22:22:26.590795',8),(18,'GinÃ¡stica Laboral','ExercÃ­cios preventivos para o ambiente de trabalho.',2,'video_externo','','','https://www.youtube.com/watch?v=dQw4w9WgXcQ','',12,1,1,'2026-03-07 22:22:26.609463',8),(20,'ClassificaÃ§Ã£o ABNT NBR 10004','Classes I (perigosos) e II (nÃ£o perigosos) de resÃ­duos sÃ³lidos.',1,'video_externo','','','https://www.youtube.com/watch?v=dQw4w9WgXcQ','',15,1,1,'2026-03-07 22:25:49.731497',10),(21,'IntroduÃ§Ã£o Ã  NR-35','Campo de aplicaÃ§Ã£o, definiÃ§Ãµes e responsabilidades.',1,'video_externo','','','https://www.youtube.com/watch?v=dQw4w9WgXcQ','',20,1,1,'2026-03-07 22:28:37.267412',11),(22,'AnÃ¡lise de Risco e PermissÃ£o de Trabalho','Como elaborar a AR e a PT para trabalho em altura.',2,'texto','<h3>AnÃ¡lise de Risco (AR)</h3>\n<p>Deve ser realizada <strong>antes de qualquer atividade</strong> em altura e incluir:</p>\n<ul>\n    <li>IdentificaÃ§Ã£o dos riscos</li>\n    <li>AvaliaÃ§Ã£o da exposiÃ§Ã£o</li>\n    <li>Medidas de controle</li>\n    <li>Sistemas de proteÃ§Ã£o contra quedas</li>\n</ul>\n<h3>PermissÃ£o de Trabalho (PT)</h3>\n<p>Documento